    /// <summary>
    /// Authors the Solutions Architect course in code. The single seam where, later, content can be loaded
    /// from ScriptableObjects/JSON instead — callers only ever see <see cref="CourseSpec"/>.
    ///
    /// Two lenses on the same topic:
    ///  - Architecture view: real AWS topology + icons, plain-AWS narration.
    ///  - Story view: a restaurant kitchen *service line* (a left-to-right flow, two parallel kitchen lines for
    ///    redundancy), with its own kitchen narration. storyPosition/storyName drive that layout.
    /// </summary>
    public static class SolutionsArchitectContent
    {
        public static CourseSpec BuildCourse()
        {
            return new CourseSpec
            {
                id = "saa-c03",
                title = "AWS Solutions Architect",
                topics = new List<TopicSpec> { BuildHighlyAvailableWebApp(), BuildStorage() }
            };
        }

        private static List<string> Ids(params string[] s) => new List<string>(s);

