            t.blocks.Add(new BlockSpec { id = "privB", kind = AwsBlockKind.PrivateSubnet, displayName = "Private subnet B", category = ServiceCategory.Networking, isContainer = true, position = new Vector3(3.5f, 0.8f, 2.0f), size = new Vector3(5.6f, 1.6f, 3.6f), storyPosition = new Vector3(2.5f, 0.7f, 2.2f), storyName = "The line B", cidr = new CidrInfo("10.0.3.0", 24), plainSummary = "The private subnet in the second AZ.", realSummary = "Private subnet 10.0.3.0/24 (eu-west-1b)." });
