            t.blocks.Add(new BlockSpec { id = "user", kind = AwsBlockKind.User, displayName = "Global user", category = ServiceCategory.Generic, position = new Vector3(0, 3.3f, -8.6f), storyPosition = new Vector3(-9f, 0.7f, 0f), storyName = "Customer", plainSummary = "A person opening your app from somewhere in the world.", realSummary = "Client HTTPS request to your domain." });
