            t.blocks.Add(new BlockSpec { id = "ec2A2", kind = AwsBlockKind.Ec2Instance, displayName = "Web server A2 (scaled out)", category = ServiceCategory.Compute, position = new Vector3(-2.4f, 0.7f, 2.7f), storyPosition = new Vector3(2.6f, 0.7f, -2.2f), storyName = "Extra cook", ports = new[] { "80" }, arn = new ArnInfo("ec2", "eu-west-1", "123456789012", "instance/i-0aa2"), plainSummary = "An instance launched by Auto Scaling during a spike.", realSummary = "EC2 added by the Auto Scaling group during a scale-out event." });
            t.blocks.Add(new BlockSpec { id = "ec2B", kind = AwsBlockKind.Ec2Instance, displayName = "Web server B", category = ServiceCategory.Compute, position = new Vector3(3.8f, 0.7f, 1.7f), storyPosition = new Vector3(1f, 0.7f, 2.2f), storyName = "Cook B", ports = new[] { "80" }, arn = new ArnInfo("ec2", "eu-west-1", "123456789012", "instance/i-0bb1"), plainSummary = "A web server in the second AZ.", realSummary = "EC2 in private subnet B." });
            t.blocks.Add(new BlockSpec { id = "rdsPrimary", kind = AwsBlockKind.RdsPrimary, displayName = "RDS primary", category = ServiceCategory.Database, position = new Vector3(-3.5f, 0.7f, 3.5f), storyPosition = new Vector3(4.6f, 0.7f, -2.2f), storyName = "Pantry", endpoint = "app-db.abc.eu-west-1.rds.amazonaws.com:5432", arn = new ArnInfo("rds", "eu-west-1", "123456789012", "db:app-db"), plainSummary = "The database — the single source of truth.", realSummary = "RDS primary (Multi-AZ) in eu-west-1a with a synchronous standby in 1b." });
