            // ---------- Connections (with the three-questions requirement detail) ----------
            t.connections.Add(new ConnectionSpec { id = "c_user_server", fromBlockId = "user", toBlockId = "singleServer", flow = ConnectionFlowKind.Request, plainSummary = "The customer orders straight from the one cook.", requirement = new ConnectionRequirement { addressNote = "the instance's public IP", permissionNote = "security group allows 80 from anywhere", securityGroup = new SecurityGroupRule("inbound", "TCP", "80", "0.0.0.0/0"), routeNote = "public subnet with a route to the internet" } });
            t.connections.Add(new ConnectionSpec { id = "c_user_r53", fromBlockId = "user", toBlockId = "route53", flow = ConnectionFlowKind.Request, plainSummary = "Where is it? The customer asks the host stand.", requirement = new ConnectionRequirement { addressNote = "your domain name app.example.com", permissionNote = "public DNS, no permission needed", routeNote = "public internet" } });
            t.connections.Add(new ConnectionSpec { id = "c_r53_cf", fromBlockId = "route53", toBlockId = "cloudfront", flow = ConnectionFlowKind.Request, plainSummary = "The host points to the nearest grab-and-go counter.", requirement = new ConnectionRequirement { addressNote = "alias record -> CloudFront", permissionNote = "public", routeNote = "global edge network" } });
            t.connections.Add(new ConnectionSpec { id = "c_cf_alb", fromBlockId = "cloudfront", toBlockId = "alb", flow = ConnectionFlowKind.Request, plainSummary = "Not ready-made? The counter sends the order to the pass.", requirement = new ConnectionRequirement { addressNote = "ALB DNS app-alb-123.eu-west-1.elb.amazonaws.com", permissionNote = "ALB SG allows 443 from the internet", securityGroup = new SecurityGroupRule("inbound", "TCP", "443", "0.0.0.0/0"), routeNote = "ALB sits in public subnets with a route to the internet gateway" } });
            t.connections.Add(new ConnectionSpec { id = "c_alb_ec2A", fromBlockId = "alb", toBlockId = "ec2A", flow = ConnectionFlowKind.Request, plainSummary = "The pass calls the ticket to a free cook.", requirement = new ConnectionRequirement { addressNote = "instance registered in the target group", permissionNote = "instance SG allows 80 from the ALB's SG", securityGroup = new SecurityGroupRule("inbound", "TCP", "80", "alb SG"), routeNote = "same VPC; private subnet reachable from the ALB's subnets" } });
            t.connections.Add(new ConnectionSpec { id = "c_alb_ec2A2", fromBlockId = "alb", toBlockId = "ec2A2", flow = ConnectionFlowKind.Request, plainSummary = "The new cook is added to the rota and takes tickets.", requirement = new ConnectionRequirement { addressNote = "auto-registered target", permissionNote = "inherits the instance SG", securityGroup = new SecurityGroupRule("inbound", "TCP", "80", "alb SG"), routeNote = "same VPC private subnet" } });
